use std::process::Command; use crate::error::VsgError; pub struct VideoDiffResult{pub delay_ms:i64,pub error:Option<f64>} pub fn run_videodiff(p:&str, rv:&str, ov:&str)->Result<VideoDiffResult,VsgError>{ let out=Command::new(p).arg(rv).arg(ov).output().map_err(|e| VsgError::Process(format!("spawn videodiff: {}",e)))?; if !out.status.success(){return Err(VsgError::Process(format!("videodiff failed")));} let s=String::from_utf8_lossy(&out.stdout); let mut last=String::new(); for line in s.lines().rev(){ if line.contains("[Result]")&&(line.contains("ss:")||line.contains("itsoffset:")){last=line.to_string();break;}} if last.is_empty(){ last=s.lines().last().unwrap_or("").to_string(); } let lower=last.to_lowercase(); let mut delay_ms: i64=0; let mut err=None; if let Some(i)=lower.find("ss") { if let Some(c)=lower[i..].find(':'){ if let Some(e)=lower[i+c+1..].find('s'){ if let Ok(v)=lower[i+c+1..i+c+1+e].trim().parse::<f64>(){ delay_ms=-(v*1000.0).round() as i64; }}}} if let Some(i)=lower.find("itsoffset") { if let Some(c)=lower[i..].find(':'){ if let Some(e)=lower[i+c+1..].find('s'){ if let Ok(v)=lower[i+c+1..i+c+1+e].trim().parse::<f64>(){ delay_ms=(v*1000.0).round() as i64; }}}} if let Some(i)=lower.find("error"){ if let Some(c)=lower[i..].find(':'){ let rest=&lower[i+c+1..]; let num=rest.split_whitespace().next().unwrap_or(""); if let Ok(v)=num.trim().parse::<f64>(){ err=Some(v); }}} Ok(VideoDiffResult{delay_ms,error:err}) }